import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { misAPI } from '../services/api';
import {
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from 'recharts';

export const MISPage = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (user?.role !== 'manager') {
      navigate('/dashboard');
      return;
    }

    const fetchMISData = async () => {
      try {
        setLoading(true);
        const response = await misAPI.getStats();

        console.log("MIS DATA:", response.data); // ✅ debug safe

        setData(response?.data || {});
        setError('');
      } catch (err) {
        console.error("MIS ERROR:", err);
        setError(err?.response?.data?.message || 'Failed to fetch MIS data');
      } finally {
        setLoading(false);
      }
    };

    fetchMISData();
  }, [user, navigate]);

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  const handleRetry = () => {
    window.location.reload(); // simple retry
  };

  const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884D8'];

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <p className="text-gray-600 text-lg">Loading MIS reports...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center">
        <div className="bg-red-100 border border-red-400 text-red-700 p-4 rounded mb-4">
          {error}
        </div>
        <button
          onClick={handleRetry}
          className="px-4 py-2 bg-blue-600 text-white rounded-lg"
        >
          Retry
        </button>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      {/* Header */}
      <header className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">📊 MIS Reports</h1>
            <p className="text-gray-600 mt-1">Performance & Progress Dashboard</p>
          </div>
          <div className="flex gap-4">
            <button
              onClick={() => navigate('/dashboard')}
              className="px-4 py-2 bg-blue-600 text-white rounded-lg"
            >
              Back
            </button>
            <button
              onClick={handleLogout}
              className="px-4 py-2 bg-red-600 text-white rounded-lg"
            >
              Logout
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">

        {/* ✅ SAFE CHECK */}
        {data?.summary && (
          <>
            {/* Summary */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
              <StatCard title="Total Tasks" value={data.summary.totalTasks} color="blue" />
              <StatCard title="Completed" value={data.summary.completedTasks} color="green" extra={`${data.summary.completionRate}%`} />
              <StatCard title="Overdue" value={data.summary.overdueTasks} color="red" />
              <StatCard title="Upcoming" value={data.summary.upcomingTasks} color="yellow" />
            </div>

            {/* Charts */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">

              {/* Pie */}
              <ChartCard title="Task Status">
                <ResponsiveContainer width="100%" height={300}>
                  <PieChart>
                    <Pie
                      data={[
                        { name: 'Pending', value: data.summary.pendingTasks },
                        { name: 'In Progress', value: data.summary.inProgressTasks },
                        { name: 'Completed', value: data.summary.completedTasks },
                      ]}
                      dataKey="value"
                      outerRadius={80}
                      label
                    >
                      <Cell fill="#FFBB28" />
                      <Cell fill="#8884D8" />
                      <Cell fill="#00C49F" />
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </ChartCard>

              {/* Department */}
              <ChartCard title="Department Tasks">
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data.departmentStats || []}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="_id" />
                    <YAxis />
                    <Tooltip />
                    <Bar dataKey="total" fill="#8884d8" />
                    <Bar dataKey="completed" fill="#00C49F" />
                  </BarChart>
                </ResponsiveContainer>
              </ChartCard>

            </div>

            {/* Employee Table */}
            <div className="bg-white p-6 rounded-lg shadow">
              <h2 className="text-xl font-bold mb-4">Employee Performance</h2>

              {(data.employeePerformance || []).length === 0 ? (
                <p className="text-gray-500">No data available</p>
              ) : (
                <table className="w-full">
                  <thead className="bg-gray-100">
                    <tr>
                      <th className="p-2">Employee</th>
                      <th>Assigned</th>
                      <th>Completed</th>
                      <th>Rate</th>
                    </tr>
                  </thead>
                  <tbody>
                    {data.employeePerformance.map((emp, i) => (
                      <tr key={i} className="text-center border-b">
                        <td className="p-2 font-semibold">{emp.employeeName}</td>
                        <td>{emp.totalAssigned}</td>
                        <td className="text-green-600">{emp.completed}</td>
                        <td>{emp.completionRate}%</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>

          </>
        )}

      </main>
    </div>
  );
};

/* 🔧 Small reusable components (NO logic change) */

const StatCard = ({ title, value, color, extra }) => (
  <div className="bg-white p-6 rounded-lg shadow">
    <p className="text-gray-600 text-sm">{title}</p>
    <p className={`text-3xl font-bold text-${color}-600`}>{value || 0}</p>
    {extra && <p className="text-sm text-gray-500">{extra}</p>}
  </div>
);

const ChartCard = ({ title, children }) => (
  <div className="bg-white p-6 rounded-lg shadow">
    <h2 className="text-lg font-bold mb-4">{title}</h2>
    {children}
  </div>
);
